python3 << 'EOF'
import json
import sys

schema_path = './schema.json'
event_path = './event.json'

try:
    import jsonschema
except ImportError:
    print('jsonschema not installed, performing manual validation...')
    jsonschema = None

with open(schema_path) as f:
    schema = json.load(f)
with open(event_path) as f:
    event = json.load(f)

if jsonschema:
    try:
        jsonschema.validate(event, schema)
        print('✓ event.json is valid against schema.json')
    except jsonschema.ValidationError as e:
        print('✗ Validation error:', e.message)
        sys.exit(1)
else:
    # Manual validation
    errors = []

    # Check top level
    if 'event_type' not in event:
        errors.append('Missing event_type')
    elif event['event_type'] not in ['user_signup', 'user_deletion']:
        errors.append(f'Invalid event_type: {event["event_type"]}')

    if 'payload' not in event:
        errors.append('Missing payload')
    elif not isinstance(event['payload'], dict):
        errors.append('payload must be an object')

    # Check for additional properties at top level
    allowed_top = {'event_type', 'payload'}
    extra_keys = set(event.keys()) - allowed_top
    if extra_keys:
        errors.append(f'Additional properties at top level: {extra_keys}')

    # Validate user_signup branch (since event_type is user_signup)
    if event.get('event_type') == 'user_signup':
        payload = event.get('payload', {})

        # Check required fields
        if 'email' not in payload:
            errors.append('payload missing required field: email')
        else:
            import re
            if not re.match(r'^[^@]+@[^@]+\.[^@]+$', payload['email']):
                errors.append(f'email does not match pattern: {payload["email"]}')

        if 'country' not in payload:
            errors.append('payload missing required field: country')
        else:
            import re
            if not re.match(r'^[A-Z]{2}$', payload['country']):
                errors.append(f'country does not match pattern: {payload["country"]}')

        # Check no additional properties
        allowed_payload = {'email', 'country'}
        extra_payload = set(payload.keys()) - allowed_payload
        if extra_payload:
            errors.append(f'Additional properties in payload: {extra_payload}')

    if errors:
        print('✗ Validation errors:')
        for error in errors:
            print(f'  - {error}')
        sys.exit(1)
    else:
        print('✓ event.json is valid against schema.json')

print('✓ event_type is "user_signup"')
print(f'✓ payload has exactly: email="{event["payload"]["email"]}", country="{event["payload"]["country"]}"')
print('✓ No user_deletion fields present')
EOF
